import React from 'react';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import LoginForm from './components/LoginForm';
import UserDashboard from './components/UserDashboard';
import MainRedactorDashboard from './components/MainRedactorDashboard';
import EngineerDashboard from './components/EngineerDashboard';

const App1 = () => {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          <Route path="/login" element={<LoginForm />} />
          <Route path="/user-dashboard" element={<ProtectedRoute><UserDashboard /></ProtectedRoute>} />
          <Route path="/main-redactor-dashboard" element={<ProtectedRoute><MainRedactorDashboard /></ProtectedRoute>} />
          <Route path="/engineer-dashboard" element={<ProtectedRoute><EngineerDashboard /></ProtectedRoute>} />
          <Route path="*" element={<Navigate to="/login" />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
};

const PrivateRoute = ({ component: Component, ...rest }) => {
  const { isAuthenticated } = useAuth();
  return (
    <Route
      {...rest}
      render={(props) =>
        isAuthenticated ? (
          <Component {...props} />
        ) : (
          <Redirect to="/login" />
        )
      }
    />
  );
};

const App = () => {
  return (
    <AuthProvider>
      <Router>
        <Switch>
          <Route path="/login" component={LoginForm} />
          <PrivateRoute path="/dashboard" component={UserDashboard} />
          <Redirect from="/" to="/login" />
        </Switch>
      </Router>
    </AuthProvider>
  );
};

const ProtectedRoute = ({ children }) => {
  const { user } = useAuth();

  if (!user) {
    return <Navigate to="/login" />;
  }

  if (user.role === 'user') {
    return <Navigate to="/user-dashboard" />;
  } else if (user.role === 'main_redactor') {
    return <Navigate to="/main-redactor-dashboard" />;
  } else if (user.role === 'engineer') {
    return <Navigate to="/engineer-dashboard" />;
  }

  return children;
};

export default App;
